26	    it("returns base premium plus fee for a single staff (80 + 5 = 85)", () => {
27	      const result = quote(
28	        { yearsWithMHPCO: 0 },
29	        [{ type: "staff", material: "oak", enchantment: 0, cursed: false }],
30	        false
31	      );
