53	  });
54	
55	  describe("quote - component premiums", () => {
56	    it("returns 25G base premium per component (e.g. 2 runes = 50)", () => {
57	      const result = quote(
58	        { yearsWithMHPCO: 0 },
59	        [
60	          { type: "rune", material: "stone", enchantment: 0, cursed: false },
61	          { type: "rune", material: "stone", enchantment: 0, cursed: false },
