68	      const result = quote(
69	        { yearsWithMHPCO: 0 },
70	        [
71	          { type: "rune", material: "stone", enchantment: 0, cursed: false },
72	          { type: "rune", material: "stone", enchantment: 0, cursed: false },
73	          { type: "rune", material: "stone", enchantment: 0, cursed: false },
74	        ],
75	        false
76	      );
77	      expect(result).toBe(65);
78	    });
79	    it("does not apply block for 4 alike components (4 runes = 100)", () => {
80	      const result = quote(
81	        { yearsWithMHPCO: 0 },
82	        [
83	          { type: "rune", material: "stone", enchantment: 0, cursed: false },
84	          { type: "rune", material: "stone", enchantment: 0, cursed: false },
85	          { type: "rune", material: "stone", enchantment: 0, cursed: false },
86	          { type: "rune", material: "stone", enchantment: 0, cursed: false },
87	        ],
88	        false
89	      );
90	      expect(result).toBe(105);
91	    });
92	    it("does not apply block for 3 components of different types (2 runes + 1 moonstone = 75)", () => {
93	      const result = quote(
94	        { yearsWithMHPCO: 0 },
95	        [
96	          { type: "rune", material: "stone", enchantment: 0, cursed: false },
97	          { type: "rune", material: "stone", enchantment: 0, cursed: false },
98	          { type: "moonstone", material: "stone", enchantment: 0, cursed: false },
99	        ],
100	        false
101	      );
102	      expect(result).toBe(80);
103	    });
104	    it("applies separate blocks for 3 runes and 3 moonstones (120)", () => {
105	      const result = quote(
106	        { yearsWithMHPCO: 0 },
107	        [
108	          { type: "rune", material: "stone", enchantment: 0, cursed: false },
109	          { type: "rune", material: "stone", enchantment: 0, cursed: false },
110	          { type: "rune", material: "stone", enchantment: 0, cursed: false },
111	          { type: "moonstone", material: "stone", enchantment: 0, cursed: false },
112	          { type: "moonstone", material: "stone", enchantment: 0, cursed: false },
113	          { type: "moonstone", material: "stone", enchantment: 0, cursed: false },
