119	  });
120	
121	  describe("quote - item-level modifiers", () => {
122	    it("adds 50% cursed surcharge to the cursed item's base premium only", () => {
123	      const result = quote(
124	        { yearsWithMHPCO: 0 },
125	        [
126	          { type: "sword", material: "steel", enchantment: 0, cursed: true },
127	          { type: "amulet", material: "silver", enchantment: 0, cursed: false },
128	        ],
129	        false
130	      );
131	      // sword base 100 + curse 50 + amulet base 60 = 210 + 5 fee = 215
132	      // (policy modifiers not yet applied in this test)
