134	    });
135	    it.todo("adds 30% high-enchantment surcharge for enchantment level >= 5");
136	    it.todo("applies both cursed and high-enchantment surcharges to the same item");
137	    it.todo("does not apply high-enchantment surcharge for enchantment level 4");
138	  });
139	
140	  describe("quote - policy-level modifiers", () => {
141	    it.todo("applies 10% first-insurance surcharge on the policy base premium");
142	    it.todo("applies 20% loyalty discount for customer with >= 2 years");
143	    it.todo("applies 15% follow-up discount on second quote");
144	    it.todo("applies first-insurance surcharge even for long-standing customers");
145	  });
146	
147	  describe("quote - rounding", () => {
148	    it.todo("rounds premium up in MHPCO's favor (ceiling)");
149	  });
150	
151	  describe("quote - integration", () => {
152	    it.todo("newcomer with cursed sword: 165G");
153	    it.todo("long-standing customer second contract with cursed high-enchantment sword: 160G");
154	  });
155	
156	  describe("claim - basic payout", () => {
157	    it.todo("applies 100G deductible per damaged item");
158	    it.todo("fully reimburses dragon-material item damage minus deductible");
159	    it.todo("reimburses at 50% for enchantment >= 8 then applies deductible");
160	    it.todo("applies 50% rule when both dragon material and enchantment >= 8");
161	    it.todo("does not apply enchantment clause for enchantment < 8");
162	  });
163	
164	  describe("claim - cap", () => {
165	    it.todo("caps total payout at twice the insurance sum");
166	    it.todo("tracks remaining cap across successive claims on same policy");
167	  });
168	
169	  describe("claim - multiple items", () => {
170	    it.todo("applies deductible separately per damaged item in same event");
171	    it.todo("handles damage to component (rune) with deductible");
172	  });
173	
174	  describe("claim - rounding", () => {
175	    it.todo("rounds payout down in MHPCO's favor (floor)");
176	  });
177	
178	  describe("error handling", () => {
179	    it.todo("rejects unknown item type in quote");
180	    it.todo("rejects claim for item not in policy");
181	    it.todo("rejects claim with more damage entries than insured items of that type");
182	    it.todo("rejects negative damage amount");
183	  });
184	
185	  describe("CLI integration", () => {
186	    it.todo("reads scenario JSON from stdin and writes results JSON to stdout");
187	    it.todo("processes sequential quote and claim steps referencing policy by index");
188	  });
189	});
