1	const PROCESSING_FEE = 5;
2	
3	interface Item {
4	  type: string;
5	  material: string;
6	  enchantment: number;
7	  cursed: boolean;
8	}
9	
10	const BASE_PREMIUMS: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const BLOCK_SIZE = 3;
21	const BLOCK_PREMIUM = 60;
22	
23	const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
24	
25	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
26	
27	const componentBlockPremium = (type: string, count: number): number =>
28	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
29	
30	const itemsPremium = (items: Item[]): number => {
31	  const components: Item[] = [];
32	  const nonComponents: Item[] = [];
33	  for (const item of items) {
34	    (isComponent(item) ? components : nonComponents).push(item);
35	  }
36	
37	  const counts: Record<string, number> = {};
38	  for (const item of components) {
39	    counts[item.type] = (counts[item.type] ?? 0) + 1;
40	  }
41	
42	  const mainPremium = nonComponents.reduce((sum, item) => {
43	    const base = basePremium(item);
44	    const curseSurcharge = item.cursed ? base * 0.5 : 0;
45	    return sum + base + curseSurcharge;
46	  }, 0);
47	  const componentTotal = Object.entries(counts).reduce(
48	    (sum, [type, count]) => sum + componentBlockPremium(type, count),
49	    0
50	  );
51	  return mainPremium + componentTotal;
52	};
53	
54	export const quote = (
55	  customer: { yearsWithMHPCO: number },
56	  items: Item[],
57	  isFollowUp: boolean
58	): number => {
59	  const premium = itemsPremium(items);
60	  return premium + PROCESSING_FEE;
61	};
